}
brute3(p + 1, en, k, s);
brute3(p + 1, en, k, s + b[p]);
}
void solveMITM() {
sz[0] = sz[1] = 0;
brute3(0, n / 2, 0, 0);
brute3(n / 2, n, 1, 0);
sort(c[0], c[0] + sz[0]);
sort(c[1], c[1] + sz[1]);
int l = sz[1], r = sz[1];
for (int i = 0; i &lt; sz[0]; i++) {
